#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(string s) {
        string res;
        int n = s.size();
        for (int i = 0; i < n; ) {
            if (isspace(s[i])) {
                res.push_back(s[i]);
                ++i;
            } else {
                int j = i;
                while (j < n && !isspace(s[j])) ++j;
                // reverse word s[i:j]
                for (int k = j - 1; k >= i; --k) res.push_back(s[k]);
                i = j;
            }
        }
        string rev = res;
        reverse(rev.begin(), rev.end());
        return rev == res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string line;
    // read first line (length) and discard
    if (!getline(cin, line)) return 0;
    // read the actual string line (may be empty)
    string s;
    if (!getline(cin, s)) s = "";
    Solution sol;
    bool ans = sol.solve(s);
    cout << (ans ? "true" : "false");
    return 0;
}
